import React, { Fragment, useState } from 'react';
import './Login.css';

const Login = ({ setAuth }) => {
  // State to hold form data
  const [formData, setFormData] = useState({
    e_mail: '',
    user_password: ''
  });

  // onChange function to update state
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Function to handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Make a POST request to the login endpoint (not implemented in this code snippet)
      // Here you would handle the login logic with your backend
      
      // Assuming login is successful, set authentication to true
      setAuth(true);
    } catch (error) {
      // Handle any errors that occur during the request
      console.error('Error:', error);
    }
  };

  return (
    <Fragment>
      <div className="login-container">
        <h1 className="login-title">Login</h1>
        <form className="login-form" onSubmit={handleSubmit}>
          <input
            className="login-input"
            type="email"
            name="e_mail"
            placeholder="Email"
            onChange={handleChange}
            value={formData.e_mail}
            required
          />
          <input
            className="login-input"
            type="password"
            name="user_password"
            placeholder="Password"
            onChange={handleChange}
            value={formData.user_password}
            required
          />
          <button className="login-button" type="submit">Login</button>
        </form>
      </div>
    </Fragment>
  );
};

export default Login;
